function on.charIn(ch)
    if ch == "u" and ndless then
        ndless.uninst()
    end
    if ch == "h" then
        help = not help
    end
    platform.window:invalidate()
end

function on.enterKey()
    help = false
    platform.window:invalidate()
end
on.escapeKey = on.enterKey

